// Generated by OrchestKit Claude Plugin
// Created: 2026-05-20

/**
 * Cross-session state bus — schema + read/write helpers (#1885).
 *
 * Each session publishes its own distilled state to
 *   ~/.claude/state/orchestkit/<repo-slug>/<session-id>.json
 *
 * The PUBLISHER side (posttool/bash hook) writes structural-event
 * milestones (git commit, git push, gh pr create/merge/ready) into the
 * file atomically. The FINALIZER side (SessionEnd hook) marks the
 * terminal status.
 *
 * Any session — in any repo — can READ another session's file with a
 * plain `Read` tool call. That's the whole point: 1 tool-use instead of
 * the 6-grep ceremony documented in #1885.
 *
 * Design constraints:
 *   • We do NOT parse CC's transcript JSONL — that would couple us to
 *     CC internals (#1890's "don't wrap CC" rule).
 *   • Each session writes only to ITS OWN file — no cross-session
 *     writes, no shared mutable state, no locks.
 *   • Atomic write via tmp-file + rename — never leaves a half-written
 *     file readable.
 *   • File format is the contract — any reader is a plain fs read.
 */

import { existsSync, mkdirSync, readFileSync, renameSync, writeFileSync } from 'node:fs';
import { basename, dirname, join } from 'node:path';
import { homedir } from 'node:os';

/** Terminal-or-running status the publisher / finalizer writes. */
export type SessionStateStatus = 'running' | 'stopped' | 'completed' | 'error';

/** A structural commit recorded from `git commit` Bash output. */
export interface CommitRef {
  /** Short or long sha as it appears in the command output. */
  sha: string;
  /** First line of the commit message. */
  msg: string;
}

/** A structural push recorded from `git push` Bash output. */
export interface PushRef {
  /** Branch being pushed (best-effort extraction from `git push origin <branch>`). */
  branch: string;
  /** Ref / sha being pushed if known; falls back to the branch. */
  ref: string;
}

/** A PR opened / merged / readied recorded from `gh pr …` Bash output. */
export interface PrRef {
  number: number;
  url: string;
  /** Last known PR state captured from gh output. */
  state: 'open' | 'closed' | 'merged' | 'draft' | string;
}

/**
 * The on-disk JSON shape. All optional fields default to null when never
 * observed in the session — readers should not assume any field is set.
 */
export interface SessionState {
  /** Repo slug (basename of project dir). */
  repo: string;
  /** Session id, also the basename of the state file. */
  session_id: string;
  /** ISO-8601 timestamp of session start (set on first write). */
  started_at: string;
  /** ISO-8601 timestamp of last state write — proxy for liveness. */
  last_heartbeat: string;
  /** Live status. */
  status: SessionStateStatus;
  /** Most recent local commit observed via `git commit`. */
  last_commit: CommitRef | null;
  /** Most recent `git push` observed. */
  last_push: PushRef | null;
  /** Most recent PR opened/merged/readied via `gh pr`. */
  last_pr: PrRef | null;
}

/** Root directory we write to. */
export function stateRootDir(home: string = homedir()): string {
  return join(home, '.claude', 'state', 'orchestkit');
}

/**
 * Derive a repo slug from a project working directory.
 * Just the basename — matches what humans see in cmux / tmux titles.
 */
export function repoSlugFromCwd(cwd: string): string {
  return basename(cwd);
}

/** Absolute path of the state file for one session. */
export function getStateFilePath(
  repoSlug: string,
  sessionId: string,
  home: string = homedir(),
): string {
  return join(stateRootDir(home), repoSlug, `${sessionId}.json`);
}

/**
 * Read an existing state file. Returns null when missing or unreadable —
 * callers must handle the "first write" case where no prior state exists.
 */
export function readSessionState(path: string): SessionState | null {
  if (!existsSync(path)) return null;
  try {
    const raw = readFileSync(path, 'utf8');
    const obj = JSON.parse(raw);
    if (!obj || typeof obj !== 'object') return null;
    return obj as SessionState;
  } catch {
    return null;
  }
}

/**
 * Write a state file atomically: write to <path>.tmp then rename.
 * Creates parent dirs lazily. Best-effort — failures are swallowed so the
 * publisher hook never blocks Claude.
 */
export function writeSessionStateAtomic(path: string, state: SessionState): boolean {
  try {
    mkdirSync(dirname(path), { recursive: true });
    const tmp = `${path}.tmp`;
    writeFileSync(tmp, `${JSON.stringify(state, null, 2)}\n`, 'utf8');
    renameSync(tmp, path);
    return true;
  } catch {
    return false;
  }
}

/**
 * Convenience: load existing state (or build a fresh one) and merge an
 * update. The merge is shallow on top-level fields — caller passes only
 * the fields it knows.
 */
export function mergeSessionState(
  existing: SessionState | null,
  update: Partial<SessionState>,
  fallbackRepo: string,
  fallbackSessionId: string,
  now: string = new Date().toISOString(),
): SessionState {
  const base: SessionState = existing ?? {
    repo: fallbackRepo,
    session_id: fallbackSessionId,
    started_at: now,
    last_heartbeat: now,
    status: 'running',
    last_commit: null,
    last_push: null,
    last_pr: null,
  };
  return {
    ...base,
    ...update,
    // last_heartbeat ALWAYS bumps on a merge — it's the liveness proxy.
    last_heartbeat: update.last_heartbeat ?? now,
  };
}
